/****
 * General Validation Secondaries - Deal Team
 * by Telmo Chiri
 ****/
let validation = {
    isValid: true,
    message: ''
};
let dealType = this.PE_DEAL_TYPE;
if (dealType == 'Secondary') {
    if (this.PE_SECONDARY_FUNDS_LOOP.length == 0) {
        validation.isValid = false;
        validation.message += "You must add at least one record.<br>";
    }
    $.each(this.PE_SECONDARY_FUNDS_LOOP, function(index, fund) {
        //fields no longer are in the loop
        if (0 && (fund.PE_SECONDARY_GP == '' || fund.PE_SECONDARY_GP == null) && (fund.PE_SECONDARY_NEW_GP == '' || fund.PE_SECONDARY_NEW_GP == null)) {
            validation.isValid = false;
            validation.message += "Record " + (index+1) + " must have at least one GP or New GP selected.<br>";
        }
    });
}
if (dealType == 'Primary') {
    //fields no longer are in the loop
    if (0 && this.PE_DEAL_TYPE == "Primary" && this.PE_PRIMARY_FUND_CURRENCY == "Other" 
        && (this.PE_PRIMARY_FUND_OTHER_CURRENCY == '' || this.PE_PRIMARY_FUND_OTHER_CURRENCY == null)) {
        validation.isValid = false;
        validation.message += "The Fund Other Currency is required.<br>";
    }
    //fields no longer are in the loop
    if (0 && (this.PE_PRIMARY_GP == '' || this.PE_PRIMARY_GP == null) && (this.PE_PRIMARY_NEW_GP == '' || this.PE_PRIMARY_NEW_GP == null)) {
        validation.isValid = false;
        validation.message += "At least one GP or New GP is required.<br>";
    }
}
if (dealType == 'Direct') {
    //fields no longer are in the loop
    if (0 && (this.PE_DIRECT_FUND_GP == '' || this.PE_DIRECT_FUND_GP == null) && (this.PE_DIRECT_FUND_NEW_GP == '' || this.PE_DIRECT_FUND_NEW_GP == null)) {
        validation.isValid = false;
        validation.message += "At least one GP or New GP is required.<br>";
    }
}

return validation;

/*
